qry:select.qry:xquery:
				for $r in sql(' 
SELECT 
	LIQ14.oi_concepto, 
	LIQ14.c_concepto, 
	LIQ14.d_concepto,
	LIQ14.c_version,  
	LIQ02.c_grupo_tliq,
	LIQ02.d_grupo_tliq,  
	LIQ12.d_tipo_concepto, 
	LIQ13.d_clase_concepto,   
	LIQ13.c_clase_concepto, 
	LIQ24.d_grupo_empresa,  
	LIQ24.c_grupo_empresa, 
	LIQ14.ca_fig_recibo, 
	LIQ14.ca_acum_ganancia,
	LIQ14.n_coef_ganancia, 
	LIQ14.l_activo,  
	LIQ14.l_ej_ajuste,  
	LIQ14.l_retroactivo, 
	LIQ14.l_interno,   
	{%? (#SOURCE:@l_incluir='1') {% LIQ14.t_formula, %} {% %} %}
	LIQ14.o_concepto,
	LIQ14.e_secuencia as e_secuencia,   
	LIQ14.e_etapa,
	E.c_equivalencia,
	E.l_informa,
	IIFISNULL(E.e_lsd, \'\') as e_lsd                                                       
FROM 
	LIQ14_CONCEPTOS as LIQ14, 
	LIQ02_GRUPOS_TLIQ as LIQ02,
	LIQ12_TIPOS_CONC as LIQ12,
	LIQ13_CLASES_CONC as LIQ13,
	LIQ24_GRUPOS_EMPRE as LIQ24,
	LIQ14_EQUIVALENCIA  as E
JOIN
	LIQ14.oi_grupo_tliq left outer LIQ02.oi_grupo_tliq,
	LIQ14.oi_tipo_concepto left outer LIQ12.oi_tipo_concepto, 
	LIQ14.oi_clase_concepto left outer LIQ13.oi_clase_concepto,
	LIQ14.oi_grupo_empresa left outer LIQ24.oi_grupo_empresa,
	LIQ14.oi_concepto LEFT OUTER E.oi_concepto
WHERE 

  1=1
  {%? (string(#SOURCE:CONCEPTOS/CONCEPTO/@id)!='') 
  	{% AND LIQ14.OI_CONCEPTO in ({%=string(#SOURCE:CONCEPTOS/CONCEPTO/@id) %}) 
  	%} 
  	{%  %} 
  %}

  {%? (#SOURCE:@cod_desde!='') 
  	{% AND LIQ14.c_concepto >= {#SOURCE:@cod_desde} 
  	%} 
  	{%  %}
  %}

  {%? (#SOURCE:@cod_hasta!='') 
  	{% AND LIQ14.c_concepto <= {#SOURCE:@cod_hasta} 
  	%} 
  	{%  %}
  %}


  {%? (#SOURCE:@oi_tipo_concepto!='') 
  	{% AND LIQ14.oi_tipo_concepto = {#SOURCE:@oi_tipo_concepto} 
  	%} 
  	{%  %}
  %}

  {%? (#SOURCE:@ca_fig_recibo!='') 
  	{% {%? (#SOURCE:@ca_fig_recibo!='1') 
  				{% AND LIQ14.ca_fig_recibo=\'N\' %} 
  				{% AND (LIQ14.ca_fig_recibo=\'S\' OR LIQ14.ca_fig_recibo=\'I\')%}
  			%} 
  	%}
  	{% %} 
  %}

  {%? (#SOURCE:@l_activo!='')	
  	{% AND LIQ14.l_activo= {#SOURCE:@l_activo} 
  	%} 
  	{% %} 
  %}

  {%? (#SOURCE:@oi_grupo_tliq!='')	
  	{% AND LIQ14.oi_grupo_tliq= {#SOURCE:@oi_grupo_tliq}
  	%} 
  	{% %} 
  %}

  {%? (#SOURCE:@oi_grupo_empresa!='')	
  	{% AND LIQ14.oi_grupo_empresa= {#SOURCE:@oi_grupo_empresa}
  	%} 
  	{% %} 
  %} 

  {%?(#SOURCE:@contiene_observacion!='')
		{% AND contain(LIQ14.d_concepto, {#SOURCE:@contiene_observacion}) 
		%}
		{% %}
	%} 

	{%? (#SOURCE:@oi_tipo_liq!='')	
  	{% AND LIQ14.oi_grupo_tliq IN (
					SELECT LIQ02.oi_grupo_tliq 
						FROM LIQ02_TLIQ_GRUPO AS LIQ02, 
								 LIQ02_GRUPOS_TLIQ AS LIQ03 
					WHERE LIQ02.oi_grupo_tliq = LIQ03.oi_grupo_tliq and 
							  LIQ02.oi_tipo_liq ={%=#SOURCE:@oi_tipo_liq%} ) 
  	%} 
  	{% %} 
  %}

	{%? (#SOURCE:@oi_empresa!='')	
  	{% AND LIQ14.oi_grupo_empresa IN (
					SELECT LIQ24.oi_grupo_empresa 
					 FROM LIQ24_EMP_GRUPOEMP AS LIQ24, 
					 			LIQ24_GRUPOS_EMPRE AS LIQ25 
					WHERE LIQ24.oi_grupo_empresa = LIQ25.oi_grupo_empresa and 
								LIQ24.oi_empresa = {%=#SOURCE:@oi_empresa%}) 
  	%} 
  	{% %} 
  %}  

ORDER BY        			
	{%? (#SOURCE:@ATRIB_ORDEN1!='')	
		{% {%=#SOURCE:@ATRIB_ORDEN1%} 
			{%? (#SOURCE:@ORDEN1!='') 
				{% {%=#SOURCE:@ORDEN1%} %} 
				{% ASC %}	
			%} 
		%} 
		{% e_secuencia ASC %} 
	%}    			
')/ROWS/ROW

				for $r in sql('
							 SELECT
									LIQ01.d_tipo_liq
               FROM
               		LIQ01_TIPOS_LIQ AS LIQ01
               WHERE
               		{%? (#SOURCE:@oi_tipo_liq!='')	
  								{% LIQ01.oi_tipo_liq= {%=#SOURCE:@oi_tipo_liq %} 
							  	%} 
							  	{% 1=2 %} 
							  	%}     
			')/ROWS/ROW

				for $r in sql('
							 SELECT
									ORG03.d_empresa
               FROM
               		ORG03_EMPRESAS AS ORG03
               WHERE
               		{%? (#SOURCE:@oi_empresa!='')	
  								{% ORG03.oi_empresa= {%=#SOURCE:@oi_empresa %} 
							  	%} 
							  	{% 1=2 %} 
							  	%}     
			')/ROWS/ROW
